<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>

        <div class="padding-t_10 p-0" id="reportstabsdata">
            <!-- LEFT MENU -->
            <div class="left-menu-tab mt-2">
                <div class="col-md-12 p-0">
                    <div class="theme-primary partition">
                        <span class="p-name text-white">{{ $t("BillingRule") }}</span>
                    </div>
                </div>

                <ul class="nav nav-pills flex-column left-tab mt-2 responivecustomtab nav-tabs">
                    <li
                        v-for="tab in tabs"
                        :key="tab.id"
                        @click="changeTab(tab)"
                        :class="{
                            'nav-item': true,
                            'active': currentTab.title === tab.title,
                            'disabled-tab': !tabsUnlocked && tab.title !== $t('BillingRuleConfiguration')
                        }"
                        :style="!tabsUnlocked && tab.title !== $t('BillingRuleConfiguration')
                            ? 'pointer-events:none;opacity:0.5;'
                            : ''"
                    >
                        <span
                            :class="{
                                'nav-link left-menu': true,
                                'active': currentTab.title === tab.title
                            }"
                        >
                            <i :class="tab.icon" class="p-1"></i>
                            {{ tab.displayName }}
                        </span>
                    </li>
                </ul>
            </div>

            <!-- RIGHT CONTENT -->
            <div class="right-content tablehead">
                <div class="tab-content z-indexfix">
                    <div class="expand-list">
                        <a href="javascript:;" class="expand-list-btn">
                            <i class="icon-solid arrow-solid-left text-white"></i>
                        </a>
                    </div>

                    <div class="theme-primary partition p-actions-expand mt-2" v-if="currentTab.title !== $t('LimitValue')">
                        <span class="p-name text-white">{{ billingRule }}</span>
                        <RouterLink :to="isBillingType ? '/BillingRule/RuleListing' : '/BillingRule/Index'" to="/BillingRule/Index"
                            class="p-action-btn text-white float-right" v-if="reqType !== 'fromServiceMapping'">
                            <i class="fa fa-angle-double-left pr-2"></i><br>
                            {{ $t("BacktoList") }}
                        </RouterLink>
                        <a v-if="isBillingType && mode == 'View'" @click="EditRuleService" class="p-action-btn text-white float-right" title="Edit">
                            <em class="fa fa-pencil"></em><br>
                            {{ $t("Edit") }}
                        </a>
                        <a v-if="currentTab.title === $t('OverrideCharge') && mode !== 'View'" @click="callAddNew"
                            class="p-action-btn text-white float-right">
                            <em class="fa fa-plus"></em><br>
                            {{ $t("Add") }}
                        </a>
                    </div>

                    <div 
                    :class="[
                            'col-md-12',
                            { 
                            border: currentTab.title !== $t('LimitValue'),
                            'float-left': currentTab.title !== $t('LimitValue')
                            }
                        ]"
                    
                    >
                        <BillingRuleConfiguration
                            v-if="currentTab.title === $t('BillingRuleConfiguration')"
                            :configurationId="configurationId"
                            :serviceId="serviceId"
                            :reqType="reqType"
                            :isBillingType="isBillingType"
                            @config-saved="handleSavedConfig"
                        />

                        <NodeConfiguration
                            v-if="currentTab.title === $t('NodeConfiguration')"
                            :configurationId="configurationId"
                            :serviceId="serviceId"
                            :reqType="reqType"
                            :mode="mode"
                            :isBillingType="isBillingType"
                             :clientId="clientId"
                             :setupId="setupId"
                        />

                        <Limit
                            v-if="currentTab.title === $t('LimitValue')"
                            :configurationId="configurationId"
                            :mode="mode"
                            :isBillingType="isBillingType"
                            :clientId="clientId"
                        />

                        <OverrideCharges
                            v-if="currentTab.title === $t('OverrideCharge')"
                            ref="overrideChargesRef"
                            :configurationId="configurationId"
                            :mode="mode"
                            :isBillingType="isBillingType"
                            :clientId="clientId"
                        />

                        <VerticalFlowChart
                            v-if="currentTab.title === $t('FlowChart1')"
                            :configurationId="configurationId"
                            :isBillingType="isBillingType" :clientId="clientId"
                        />

                        <HorizontalFlowChart
                            v-if="currentTab.title === $t('FlowChart')"
                            :configurationId="configurationId"
                            :isBillingType="isBillingType"
                        />
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataServices from "../../services/DataService";
import BillingRuleConfiguration from "./ConfigurationComponent/BillingRuleConfiguration.vue";
import Limit from "./ConfigurationComponent/Limit.vue";
import NodeConfiguration from "./ConfigurationComponent/NodeConfiguration.vue";
import VerticalFlowChart from "./ConfigurationComponent/VerticalFlowChart.vue";
import OverrideCharges from "./ConfigurationComponent/OverrideCharges.vue";
import HorizontalFlowChart from "./ConfigurationComponent/HorizontalFlowChart.vue";
import {
    locateBillingService
} from "../../services/locateBillingService";

export default {
    components: {
        BillingRuleConfiguration,
        Limit,
        NodeConfiguration,
        VerticalFlowChart,
        OverrideCharges,
        HorizontalFlowChart
    },

    props: {
        serviceId: String,
        reqType: String,
        configurationId: String,
        mode: { type: String, default: "Edit" }
    },

    data() {
        return {
            tabsUnlocked: false,
            isLoading: false,
            isBillingType: false,
            configurationId: 0,
            clientId: 0,
            mode: "Edit",
            billingRule:'',
            tabs: [
                { id: 1, title: this.$t("BillingRuleConfiguration"), displayName: this.$t("BillingRuleConfiguration"), icon: "fa fa-cogs" },
                { id: 2, title: this.$t("NodeConfiguration"), displayName: this.$t("NodeConfiguration"), icon: "fa fa-xing" },
                { id: 3, title: this.$t("LimitValue"), displayName: this.$t("LimitValue"), icon: "fa fa-circle-o-notch" },
                { id: 4, title: this.$t("OverrideCharge"), displayName: this.$t("OverrideCharge"), icon: "fa fa-deviantart" },
                { id: 5, title: this.$t("FlowChart1"), displayName: this.$t("FlowChart1"), icon: "fa fa-usb" },
                { id: 6, title: this.$t("FlowChart"), displayName: this.$t("FlowChart"), icon: "fa fa-sitemap" }
            ],

            currentTab: null,
            setupId:0
        };
    },

    async created() {
        this.isBillingType = localStorage.getItem("billingType") === "USIC";
        this.mode = this.$route.params.mode || "Edit";
        this.configurationId = parseInt(this.$route.params.id);
        this.serviceId = parseInt(this.$route.params.serviceId);
        if (this.configurationId) {
            this.tabsUnlocked = true;
            if (this.isBillingType) {
                await this.BindConfigurationData();
            }
        }

        this.currentTab =
            this.mode === "View" || this.mode === "Edit"
                ? this.tabs.find(t => t.title === this.$t("NodeConfiguration"))
                : this.tabs[0];
    },

    watch: {
        "$route.params.id": async function (newId) {
            if (newId && this.isBillingType) {
                this.configurationId = parseInt(newId);
                await this.BindConfigurationData();
            }
        }
    },

    methods: {
        EditRuleService: async function () {
            var vm = this;
            if(this.isBillingType){
                 vm.getNodeConfiguration(this.configurationId,this.serviceId,'Edit')
            }
        },
        getNodeConfiguration: function (configId,serviceId,mode) {
            let ths = this;
            var prms = `configId=${configId}&serviceId=${serviceId}&isIncludeGlobalService=true&isView=${mode}`;
            DataServices.GetNodeConfiguration(prms).then(function (res) {
                if (res?.data?.length > 0 && res.data[0]?.CONFIG_ID != null && res.data[0]?.SERVICE_ID != null) {
                    configId = res.data[0].CONFIG_ID;
                    serviceId = res.data[0].SERVICE_ID;
                    ths.$router.push({ name: 'ManageConfiguration', params: { id: configId, serviceId : serviceId,mode :'Edit' } });
                }
            });
        },
        async BindConfigurationData() {
            if (this.clientId) return; // ⛔ prevent multiple calls
            this.isLoading = true;
            const url = `configId=${this.configurationId}&isForUtilityBilling=${this.isBillingType == true ? false : true}`;
            const response = await DataServices.GetConfigurationData(url);
            if (response?.data?.length) {
                this.clientId = response.data[0].client_id;
                var billingRule = response.data[0].billing_config_name;
                this.setupId = response.data[0].setup_id
                this.BindCompanyContractClients(this.clientId,billingRule);
            }
            this.isLoading = false;
        },
        BindCompanyContractClients: async function (clientId,billingRuleName) {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                const client = vm.clientList.filter(c => c.value == clientId)[0];
                var selectedClientName = client?.text || '';
                this.billingRule = billingRuleName + '  (' + selectedClientName + ')';
               
             
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
               
               
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        changeTab(tab) {
            if (!this.tabsUnlocked && tab.title !== this.$t("BillingRuleConfiguration")) return;
            this.currentTab = tab;
        },

        handleSavedConfig(payload) {
            this.configurationId = payload.configId;
            this.tabsUnlocked = true;

            if (payload.goTo) {
                const nextTab = this.tabs.find(t => t.title === this.$t(payload.goTo));
                if (nextTab) this.currentTab = nextTab;
            }
        },

        callAddNew() {
            this.$refs.overrideChargesRef?.AddNewRow?.();
        }
    }
};
</script>

<style scoped>
.disabled-tab {
    cursor: not-allowed;
}
</style>
